import numpy as np
from copy import deepcopy

class DataLoader:
    def __init__(self, X, y, batch_size=32, shuffle=True):
        self.X = X
        self.y = y
        self.batch_size = batch_size
        self.shuffle = shuffle

    def __iter__(self):
        n = len(self.X)
        indices = np.random.permutation(n) if self.shuffle else np.arange(n)
        for start in range(0, n, self.batch_size):
            batch_idx = indices[start:start + self.batch_size]
            yield self.X[batch_idx], self.y[batch_idx]

    def __len__(self):
        return int(np.ceil(len(self.X) / self.batch_size))


class Linear:
    def __init__(self, in_f, out_f):
        scale = np.sqrt(2.0 / in_f)
        self.W = np.random.randn(out_f, in_f) * scale
        self.b = np.zeros(out_f)
        self.dW = np.zeros_like(self.W)
        self.db = np.zeros_like(self.b)
        self._x = None

    def forward(self, x):
        self._x = x
        return x @ self.W.T + self.b

    def backward(self, grad):
        self.dW = grad.T @ self._x
        self.db = grad.sum(axis=0)
        return grad @ self.W

    def params(self):
        return [(self.W, self.dW), (self.b, self.db)]


class BatchNorm:
    def __init__(self, n, eps=1e-5, momentum=0.1):
        self.gamma = np.ones(n)
        self.beta = np.zeros(n)
        self.dgamma = np.zeros(n)
        self.dbeta = np.zeros(n)
        self.eps = eps
        self.momentum = momentum
        self.running_mean = np.zeros(n)
        self.running_var = np.ones(n)
        self._cache = None

    def forward(self, x, training=True):
        if training:
            mu = x.mean(axis=0)
            var = x.var(axis=0)
            x_hat = (x - mu) / np.sqrt(var + self.eps)
            self.running_mean = (1 - self.momentum) * self.running_mean + self.momentum * mu
            self.running_var = (1 - self.momentum) * self.running_var + self.momentum * var
            self._cache = (x, x_hat, mu, var)
        else:
            x_hat = (x - self.running_mean) / np.sqrt(self.running_var + self.eps)
        return self.gamma * x_hat + self.beta

    def backward(self, grad):
        x, x_hat, mu, var = self._cache
        N = x.shape[0]
        self.dgamma = (grad * x_hat).sum(axis=0)
        self.dbeta = grad.sum(axis=0)
        dx_hat = grad * self.gamma
        std_inv = 1.0 / np.sqrt(var + self.eps)
        dx = (1.0 / N) * std_inv * (
            N * dx_hat - dx_hat.sum(axis=0) - x_hat * (dx_hat * x_hat).sum(axis=0)
        )
        return dx

    def params(self):
        return [(self.gamma, self.dgamma), (self.beta, self.dbeta)]


class Dropout:
    def __init__(self, p=0.5):
        self.p = p
        self._mask = None

    def forward(self, x, training=True):
        if training and self.p > 0:
            self._mask = (np.random.rand(*x.shape) > self.p).astype(float)
            return x * self._mask / (1.0 - self.p)
        return x

    def backward(self, grad):
        if self._mask is not None:
            return grad * self._mask / (1.0 - self.p)
        return grad


class MLP:
    def __init__(self, input_dim, hidden_dim, output_dim, dropout_p=0.3):
        self.training = True
        self.l1 = Linear(input_dim, hidden_dim)
        self.bn1 = BatchNorm(hidden_dim)
        self.drop1 = Dropout(dropout_p)
        self.l2 = Linear(hidden_dim, hidden_dim)
        self.bn2 = BatchNorm(hidden_dim)
        self.drop2 = Dropout(dropout_p)
        self.l3 = Linear(hidden_dim, output_dim)
        self._relu_mask1 = None
        self._relu_mask2 = None

    def set_training(self, training):
        self.training = training

    def _relu(self, x, layer):
        mask = (x > 0).astype(float)
        if layer == 1:
            self._relu_mask1 = mask
        else:
            self._relu_mask2 = mask
        return x * mask

    def forward(self, x):
        t = self.training
        x = self.l1.forward(x)
        x = self.bn1.forward(x, training=t)
        x = self._relu(x, 1)
        x = self.drop1.forward(x, training=t)
        x = self.l2.forward(x)
        x = self.bn2.forward(x, training=t)
        x = self._relu(x, 2)
        x = self.drop2.forward(x, training=t)
        x = self.l3.forward(x)
        return x

    def backward(self, grad):
        g = self.l3.backward(grad)
        g = self.drop2.backward(g)
        g = g * self._relu_mask2
        g = self.bn2.backward(g)
        g = self.l2.backward(g)
        g = self.drop1.backward(g)
        g = g * self._relu_mask1
        g = self.bn1.backward(g)
        self.l1.backward(g)

    def get_all_params(self):
        return (
            self.l1.params() + self.bn1.params()
            + self.l2.params() + self.bn2.params()
            + self.l3.params()
        )


class AdamOptimizer:
    def __init__(self, param_pairs, lr=1e-3, beta1=0.9, beta2=0.999, eps=1e-8):
        self.param_pairs = param_pairs
        self.lr = lr
        self.beta1 = beta1
        self.beta2 = beta2
        self.eps = eps
        self.t = 0
        self.m = [np.zeros_like(p) for p, _ in param_pairs]
        self.v = [np.zeros_like(p) for p, _ in param_pairs]

    def zero_grad(self):
        for _, g in self.param_pairs:
            g[:] = 0.0

    def step(self):
        self.t += 1
        for i, (p, g) in enumerate(self.param_pairs):
            self.m[i] = self.beta1 * self.m[i] + (1 - self.beta1) * g
            self.v[i] = self.beta2 * self.v[i] + (1 - self.beta2) * g**2
            m_hat = self.m[i] / (1 - self.beta1**self.t)
            v_hat = self.v[i] / (1 - self.beta2**self.t)
            p -= self.lr * m_hat / (np.sqrt(v_hat) + self.eps)


class EarlyStopping:
    def __init__(self, patience=10, min_delta=1e-4):
        self.patience = patience
        self.min_delta = min_delta
        self.best_loss = np.inf
        self.counter = 0
        self.best_params = None
        self.triggered = False

    def __call__(self, val_loss, model):
        if val_loss < self.best_loss - self.min_delta:
            self.best_loss = val_loss
            self.counter = 0
            self.best_params = deepcopy([(p.copy(), g.copy()) for p, g in model.get_all_params()])
        else:
            self.counter += 1
            if self.counter >= self.patience:
                self.triggered = True
        return self.triggered

    def restore_best(self, model):
        if self.best_params is not None:
            for (p, g), (bp, bg) in zip(model.get_all_params(), self.best_params):
                p[:] = bp
                g[:] = bg


class Trainer:
    def __init__(self, model, optimizer, early_stopping=None):
        self.model = model
        self.optimizer = optimizer
        self.early_stopping = early_stopping

    def mse_loss(self, pred, y):
        diff = pred - y
        loss = np.mean(diff**2)
        grad = 2.0 * diff / len(y)
        return loss, grad

    def fit(self, X, y, X_val, y_val, epochs=100, batch_size=32):
        loader = DataLoader(X, y, batch_size=batch_size, shuffle=True)
        history = {'train_losses': [], 'val_losses': []}
        for epoch in range(epochs):
            self.model.set_training(True)
            epoch_losses = []
            for X_batch, y_batch in loader:
                self.optimizer.zero_grad()
                pred = self.model.forward(X_batch)
                loss, grad = self.mse_loss(pred, y_batch)
                self.model.backward(grad)
                self.optimizer.step()
                epoch_losses.append(loss)
            train_loss = float(np.mean(epoch_losses))
            self.model.set_training(False)
            val_pred = self.model.forward(X_val)
            val_loss, _ = self.mse_loss(val_pred, y_val)
            val_loss = float(val_loss)
            history['train_losses'].append(train_loss)
            history['val_losses'].append(val_loss)
            if self.early_stopping is not None:
                if self.early_stopping(val_loss, self.model):
                    self.early_stopping.restore_best(self.model)
                    break
        return history

